
import { Component, Vue, Prop } from "vue-property-decorator";
import { TreeNode } from "@/types/tree";
import {
  calculateElementPositionOnCanvas,
  listenForPositionChangesAndGetNewPosition,
  ElementPositionOnCanvas,
  getWrapperStyle
} from "@/futurelayer/canvas/canvas-controls/element-positioning";
import { removeElement, enableElement, removePermanently } from "@/lib/futurelayer/optional-elements/optional-elements";
import Icon from "@/components/UI/Icon.vue";

@Component({
  components: {
    Icon
  }
})
export default class FutureLayerRemovableElementControls extends Vue {
  @Prop()
  element!: TreeNode;

  elementPositionOnCanvas: ElementPositionOnCanvas = false;
  cleanupListeners: () => void = () => {};

  mounted() {
    this.elementPositionOnCanvas = calculateElementPositionOnCanvas(
      this.element
    );

    this.cleanupListeners = listenForPositionChangesAndGetNewPosition(
      this.element,
      (newPosition: ElementPositionOnCanvas) => {
        this.elementPositionOnCanvas = newPosition;
      }
    );
  }

  beforeDestroy() {
    this.cleanupListeners();
  }

  get cssStyleForWrapper(): Record<string, string> {
    return getWrapperStyle(this.elementPositionOnCanvas);
  }

  get cssStyleForControls(): Record<string, string> {
    if (!this.elementPositionOnCanvas) {
      return { display: "none" };
    }

    return {
      left: `calc(${this.elementPositionOnCanvas.width} + 4px)`,
      top: `calc(${this.elementPositionOnCanvas.height} / 2)`,
      transform: "translateY(-50%)"
    };
  }

  get isRemoved(): boolean {
    return this.element.data.properties?.settings?.futurelayer?.removed === true;
  }

  toggleRemoved() {
    if (this.isRemoved) {
      enableElement(this.element.id);
    } else {
      removeElement(this.element.id);
    }
  }

  handleRemovePermanently() {
    removePermanently(this.element.id);
  }
}
