
import Vue from "vue";
import { Component, Prop } from "vue-property-decorator";
import { logEvent } from "@/util/tracking";
import Icon from "@/components/UI/Icon.vue";
import NiceButton from "@/components/UI/NiceButton.vue";

@Component({
  components: {
    Icon,
    NiceButton
  }
})
export default class FeedbackBox extends Vue {
  showFeedback = false;
  feedbackTextArea: HTMLTextAreaElement | null = null;
  feedback = "";
  rating: number | null = null;
  feedbackSent = false;

  get isValidFeedback() {
    return this.feedback.length > 0 || (this.rating && this.rating > 0);
  }

  toggle() {
    this.showFeedback = !this.showFeedback;

    this.$nextTick(() => {
      const textarea = this.$refs.feedbackTextarea as HTMLTextAreaElement;
      if (textarea) {
        textarea.focus();
      }
    });
  }

  sendFeedback() {
    if (this.feedback.length > 0) {
      logEvent("FutureLayer Feedback", {
        location: "sidebar",
        feedback: this.feedback,
        rating: this.rating
      });
      this.feedback = "";
      this.feedbackSent = true;
      this.rating = null;
      this.showFeedback = false;

      setTimeout(() => {
        this.feedbackSent = false;
      }, 3000);
    }
  }
}
