import { documentStore, uiStore } from "@/store/store";
import { TreeNode } from "@/types/tree";

export function currentlyActiveElementSupportsRemoval(): boolean {
  if (!uiStore.activeElement) return false;
  return uiStore.activeElement.data.properties?.settings?.futurelayer?.allow_removal === true;
}

export function removeElement(elementId: TreeNode['id']) {
  documentStore.unthrottledPropertyChanged({
    elementId: elementId,
    path: "settings.futurelayer.removed",
    value: true,
    meta: {
      snapshotLabel: "Disable Optional Element"
    }
  });
}

export function enableElement(elementId: TreeNode['id']) {
  documentStore.unthrottledPropertyChanged({
    elementId: elementId,
    path: "settings.futurelayer.removed",
    value: false,
    meta: {
      snapshotLabel: "Enable Optional Element"
    }
  });
}

export function removePermanently(elementId: TreeNode['id']) {
  documentStore.deleteElement({ nodeId: elementId });
}
