
import { Vue, Component, Prop } from "vue-property-decorator";
import { TemplatePreviewableItem } from "@/types/templates";
import { configStore } from "@/store/store";
import { sprintf, _doc, __ } from "@/lib/i18n";

@Component
export default class PreviewChooserNothingToPreview extends Vue {
  @Prop()
  previewItem?: TemplatePreviewableItem;

  @Prop()
  nothingToPreview!: boolean;

  get builderMode() {
    return configStore.builderMode;
  }

  get previewLabel() {
    return (
      this.previewItem?.label ||
      sprintf(
        _doc("ID %s", "%s: ID number"),
        this.previewItem?.id || __("(no title)")
      )
    );
  }
}
