
import Vue from "vue";
import { Component, Prop } from "vue-property-decorator";
import { configStore } from "@/store/store";
import { KEYBOARD_SHORTCUTS } from "@/lib/keyboard-shortcuts/global-shortcuts";
import { __ } from "@/lib/i18n";

type Shortcut = {
  shortcut: (keyof typeof KEYBOARD_SHORTCUTS)[];
  description: string;
  availableIn: ("breakdance" | "oxygen")[];
};

@Component({
  components: {}
})
export default class KeyboardShortcutsHelpModal extends Vue {
  @Prop()
  open!: boolean;

  shortcuts: Shortcut[] = [
    {
      shortcut: ["CMD_A"],
      description: __("Open add elements panel"),
      availableIn: ["breakdance", "oxygen"]
    },
    {
      shortcut: ["CMD_B"],
      description: __("Open design sets modal"),
      availableIn: ["breakdance"]
    },
    {
      shortcut: ["CMD_SHIFT_E"],
      description: __("Open structure panel"),
      availableIn: ["oxygen"]
    },
    {
      shortcut: ["CMD_SHIFT_V"],
      description: __("Open variables panel"),
      availableIn: ["oxygen"]
    },
    {
      shortcut: ["CMD_SHIFT_G"],
      description: __("Open selectors panel"),
      availableIn: ["oxygen"]
    },
    {
      shortcut: ["CMD_S"],
      description: __("Save"),
      availableIn: ["breakdance", "oxygen"]
    },
    {
      shortcut: ["CMD_Z"],
      description: __("Undo"),
      availableIn: ["breakdance", "oxygen"]
    },
    {
      shortcut: ["CMD_SHIFT_Z"],
      description: __("Redo"),
      availableIn: ["breakdance", "oxygen"]
    },
    {
      shortcut: ["CMD_C"],
      description: __("Copy the active element"),
      availableIn: ["breakdance", "oxygen"]
    },
    {
      shortcut: ["CMD_V"],
      description: __("Paste copied element"),
      availableIn: ["breakdance", "oxygen"]
    },
    {
      shortcut: ["CMD_D"],
      description: __("Duplicate the active element"),
      availableIn: ["breakdance", "oxygen"]
    },
    {
      shortcut: ["ESC"],
      description: __("De-activate the active element or close modal"),
      availableIn: ["breakdance", "oxygen"]
    },
    {
      shortcut: ["SHIFT_ESC"],
      description: __("Go to the parent of the active element"),
      availableIn: ["breakdance", "oxygen"]
    },
    {
      shortcut: ["BACKSPACE", "DELETE"],
      description: __("Delete active element"),
      availableIn: ["breakdance", "oxygen"]
    },
    {
      shortcut: ["CMD_OPTION_R"],
      description: __("Cycle to the next breakpoint"),
      availableIn: ["breakdance", "oxygen"]
    },
    {
      shortcut: ["CMD_SHIFT_SLASH", "CMD_QUESTION"],
      description: __("Show keyboard shortcuts help modal"),
      availableIn: ["breakdance", "oxygen"]
    },
    {
      shortcut: ["CMD_SHIFT_S"],
      description: __("Switch between 'scale to fit' and 'actual size' content"),
      availableIn: ["breakdance", "oxygen"]
    },
    {
      shortcut: ["CMD_E"],
      description: __("Open the rich text editor modal. Only when the Rich Text element is selected"),
      availableIn: ["breakdance", "oxygen"]
    },
    {
      shortcut: ["C_S_S"],
      description: __("Open the active element's Advanced → Custom CSS and focus it."),
      availableIn: ["breakdance"]
    },
    {
      shortcut: ["C_L_A"],
      description: __("Open the active element's Advanced → Classes autocomplete and focus it."),
      availableIn: ["breakdance"]
    },
    {
      shortcut: ["F"],
      description: __("Focus the properties search box."),
      availableIn: ["breakdance"]
    },
    {
      shortcut: ["SHIFT_F"],
      description: __("Focus the properties search box and toggle the option to search advanced settings (element properties panel only)."),
      availableIn: ["breakdance"]
    },
    {
      shortcut: ["CMD_I"],
      description: __("Toggle the modified option in the properties search box."),
      availableIn: ["breakdance"]
    },
    {
      shortcut: ["OPTION_P"],
      description: __("Toggle the preview mode."),
      availableIn: ["breakdance", "oxygen"]
    }
  ];

  get builderMode() {
    return configStore.builderMode || "breakdance";
  }

  get filteredShortcuts() {
    return this.shortcuts
      .filter(item => item.availableIn.includes(this.builderMode))
      .map(item => {
        const shortcut = item.shortcut
          .map(this.getKeyboardShortcutValue)
          .join("<br />");

        return {
          ...item,
          shortcut
        };
      });
  }

  getKeyboardShortcutValue(shortcut: keyof typeof KEYBOARD_SHORTCUTS) {
    const keys = KEYBOARD_SHORTCUTS[shortcut];
    const isMacLike = /(Mac|iPhone|iPod|iPad)/i.test(navigator.platform);
    let keyCombo = keys ? keys[0] : "";
    if (!isMacLike && keys.length == 2) {
      keyCombo = keys[1];
    }

    return keyCombo.toUpperCase().split("+").join(" + ");
  }
}
