
import Vue from "vue";
import { Component, Prop } from "vue-property-decorator";
import { logEvent } from "@/util/tracking";
import Icon from "@/components/UI/Icon.vue";

@Component({
  components: {
    Icon
  }
})
export default class FeedbackBox extends Vue {

  @Prop()
  eventProperties!: Record<string, any>;

  rating: "up" | "down" | null = null;
  feedbackSent = false;
  // When true the whole box will be hidden (after showing thank-you state)
  isHidden = false;

  /** Called when the user clicks a thumb (up/down). Sends a logEvent immediately. */
  handleThumb(direction: "up" | "down") {

    this.rating = direction;
    logEvent("FutureLayer Feedback AI", {
      rating: direction,
      ...this.eventProperties
    });

    // Show thank-you state briefly, then hide the box permanently
    this.feedbackSent = true;

    setTimeout(() => {
      // keep existing thank-you logic (toggle off state and clear rating)
      this.feedbackSent = false;
      this.rating = null;
      // hide the box so it doesn't reappear
      this.isHidden = true;
    }, 3000);
  }
}
